            continue

        pos = (nx, ny)

        # Encourage moving onto/near resources; avoid giving opponent easy access via distance term.
        if resources:
            t = target_list[0]
            d_us = man(pos, t)
            # If other resources exist, consider second option slightly to reduce dithering.
            d2 = man(pos, target_list[1]) if len(target_list) > 1 else d_us

            on_res = 1 if pos in resources else 0
            v = (on_res * 10**6) - (d_us * 2000) - (d2 * 250)
            v += (man(pos, (ox, oy)) * 35)  # don't get too close to opponent
        else:
            # When no resources: maximize distance from opponent and (slightly) run toward farthest corner.
            far_corner = max([(0, 0), (w - 1, 0), (0, h - 1), (w - 1, h - 1))],
                             key=lambda c: (man((nx, ny), c), c[0], c[1]))
            v = (man(pos, (ox, oy)) * 120) + (man(pos, far_corner) * 25)

        # Small deterministic preference to reduce oscillation: prefer moves that change x then y deterministically.
        v += (0.5 if dx == 0 else 0.1) + (0.05 if dy == 0 else 0.0)

